// Robust assembler for the four AI generations.
// Detects API failures (error bodies / empty choices) and unparseable SWOT JSON,
// and routes those jobs to "Needs Review" instead of silently shipping bad docs.
const jobData = $('P3: Prepare All AI Prompts').first().json;
const cvResponse = $('P3: OpenRouter Generate CV').first().json;
const clResponse = $('P3: OpenRouter Generate Cover Letter').first().json;
const swotResponse = $('P3: OpenRouter Generate SWOT').first().json;
const studyResponse = $('P3: OpenRouter Generate Study Guide').first().json;

function getContent(resp) {
  return (resp && resp.choices && resp.choices[0] && resp.choices[0].message)
    ? resp.choices[0].message.content : null;
}
function apiErr(resp) {
  return (resp && resp.error && resp.error.message)
    ? resp.error.message
    : ((resp && resp.choices) ? null : 'No choices returned');
}
function extractJson(raw) {
  if (raw == null) return null;
  let s = String(raw)
    .replace(/<think>[\s\S]*?<\/think>/gi, ' ')
    .replace(/```json/gi, ' ')
    .replace(/```/g, ' ');
  const a = s.indexOf('{');
  const b = s.lastIndexOf('}');
  if (a === -1 || b === -1 || b <= a) return null;
  try { return JSON.parse(s.slice(a, b + 1)); } catch (e) { return null; }
}

const cvText = getContent(cvResponse);
const clText = getContent(clResponse);
const studyText = getContent(studyResponse);
const sp = extractJson(getContent(swotResponse));

const failures = [];
if (!cvText)    failures.push('CV: ' + (apiErr(cvResponse) || 'empty'));
if (!clText)    failures.push('CoverLetter: ' + (apiErr(clResponse) || 'empty'));
if (!studyText) failures.push('StudyGuide: ' + (apiErr(studyResponse) || 'empty'));
if (!sp)        failures.push('SWOT: ' + (apiErr(swotResponse) || 'unparseable JSON'));

const generationOk = failures.length === 0;
const swot = sp || {};

const swotSummary = [
  'STRENGTHS: ' + (swot.strengths || []).map(s => s.point || s).join(' | '),
  'WEAKNESSES: ' + (swot.weaknesses || []).map(w => w.point || w).join(' | '),
  'OPPORTUNITIES: ' + (swot.opportunities || []).map(o => o.point || o).join(' | '),
  'THREATS: ' + (swot.threats || []).map(t => t.point || t).join(' | ')
].join('\n');
const improvements = (swot.top_improvements || []).join(' | ');
const interviewPrep = (swot.interview_prep || []).join(' | ');

const swotMarkdown = `# SWOT Analysis
**Role:** ${jobData.title} at ${jobData.company}
**Date:** ${new Date().toISOString().split('T')[0]}
**Match Score:** ${jobData.score}/100

## Strengths
${(swot.strengths || []).map((s, i) => `${i+1}. **${s.point || s}**\n   - Evidence: ${s.evidence || 'N/A'}\n   - Leverage: ${s.leverage || 'N/A'}`).join('\n\n')}

## Weaknesses
${(swot.weaknesses || []).map((w, i) => `${i+1}. **${w.point || w}**\n   - Impact: ${w.impact || 'N/A'}\n   - Mitigation: ${w.mitigation || 'N/A'}`).join('\n\n')}

## Opportunities
${(swot.opportunities || []).map((o, i) => `${i+1}. **${o.point || o}**\n   - Action: ${o.action || 'N/A'}`).join('\n\n')}

## Threats
${(swot.threats || []).map((t, i) => `${i+1}. **${t.point || t}**\n   - Mitigation: ${t.mitigation || 'N/A'}`).join('\n\n')}

## Top Improvements
${(swot.top_improvements || []).map((imp, i) => `${i+1}. ${imp}`).join('\n')}

## Interview Prep Tips
${(swot.interview_prep || []).map((tip, i) => `${i+1}. ${tip}`).join('\n')}

## Application Strategy
${swot.application_strategy || 'No strategy provided'}
`;

return [{
  json: {
    ...jobData,
    cv_markdown: cvText || ('CV generation failed: ' + (apiErr(cvResponse) || 'empty')),
    cover_letter_markdown: clText || ('Cover letter generation failed: ' + (apiErr(clResponse) || 'empty')),
    study_guide_markdown: studyText || ('Study guide generation failed: ' + (apiErr(studyResponse) || 'empty')),
    swot_markdown: swotMarkdown,
    swot_json: JSON.stringify(swot),
    swot_summary: swotSummary,
    top_improvements: improvements,
    interview_prep_tips: interviewPrep,
    application_strategy: swot.application_strategy || '',
    generation_ok: generationOk,
    generation_failures: failures.join(' || '),
    status: generationOk ? 'Docs Generated' : 'Needs Review'
  }
}];

// Prepare all documents as binary data for upload
const cvMarkdown = $('P3: Parse & Assemble Documents').first().json.cv_markdown;
const clMarkdown = $('P3: Parse & Assemble Documents').first().json.cover_letter_markdown;
const studyMarkdown = $('P3: Parse & Assemble Documents').first().json.study_guide_markdown;
const swotMarkdown = $('P3: Parse & Assemble Documents').first().json.swot_markdown;
const folderId = $('P3: Create Job Folder in Drive').first().json.id;
const cvFilename = $('P3: Parse & Assemble Documents').first().json.cv_filename;
const clFilename = $('P3: Parse & Assemble Documents').first().json.cl_filename;
const studyFilename = $('P3: Parse & Assemble Documents').first().json.study_filename;
const swotFilename = $('P3: Parse & Assemble Documents').first().json.swot_filename;
const allData = $('P3: Parse & Assemble Documents').first().json;

// Convert markdown to Buffer for binary upload
const cvBuffer = Buffer.from(cvMarkdown, 'utf-8');
const clBuffer = Buffer.from(clMarkdown, 'utf-8');
const studyBuffer = Buffer.from(studyMarkdown, 'utf-8');
const swotBuffer = Buffer.from(swotMarkdown, 'utf-8');

return [{
  json: {
    ...allData,
    folder_id: folderId,
    cv_filename_full: cvFilename + '.md',
    cl_filename_full: clFilename + '.md',
    study_filename_full: studyFilename + '.md',
    swot_filename_full: swotFilename + '.md'
  },
  binary: {
    cv_data: {
      data: cvBuffer.toString('base64'),
      mimeType: 'text/markdown',
